const body = $json.body ?? $json;
const data = body.data ?? {};
const key = data.key ?? {};
const message = data.message ?? {};
const instance = body.instance ?? body.instanceName ?? '';
const remoteJid = key.remoteJid ?? '';
const fromMe = key.fromMe ?? false;
if (fromMe) { return []; }
if (String(remoteJid).includes('@g.us')) { return []; }
const phone = String(remoteJid).split('@')[0].split(':')[0];
const pushName = data.pushName ?? '';
let msgType='text', textContent='', mediaBase64='', mimeType='';
if (message.conversation) textContent = message.conversation;
else if (message.extendedTextMessage && message.extendedTextMessage.text) textContent = message.extendedTextMessage.text;
if (message.audioMessage) { msgType='audio'; mimeType=message.audioMessage.mimetype||'audio/ogg'; }
else if (message.imageMessage) { msgType='image'; mimeType=message.imageMessage.mimetype||'image/jpeg'; textContent=message.imageMessage.caption||''; }
else if (message.documentMessage) { msgType='document'; mimeType=message.documentMessage.mimetype||'application/pdf'; textContent=message.documentMessage.caption||message.documentMessage.fileName||''; }
mediaBase64 = message.base64 || data.base64 || body.base64 || (message.audioMessage&&message.audioMessage.base64) || (message.imageMessage&&message.imageMessage.base64) || (message.documentMessage&&message.documentMessage.base64) || '';
const esc = s => String(s ?? '').replace(/'/g, "''");
return [{ json: { instance, phone, pushName, fromMe, msgType, textContent, mediaBase64, mimeType, phone_esc: esc(phone), pushName_esc: esc(pushName) } }];

const b64 = $('Normalizar Payload').item.json.mediaBase64;
const mime = $('Normalizar Payload').item.json.mimeType || 'audio/ogg';
if (!b64) { return [{ json: { text: '[Audio recebido, sem conteudo para transcrever]' }, _skip:true }]; }
return [{ json: {}, binary: { data: { data: b64, mimeType: mime, fileName: 'audio.ogg' } } }];

const mime = $('Normalizar Payload').item.json.mimeType || 'image/jpeg';
const b64 = $('Normalizar Payload').item.json.mediaBase64 || '';
const caption = $('Normalizar Payload').item.json.textContent || '';
const body = { model:'gpt-4o', max_tokens:500, messages:[{role:'user',content:[
  {type:'text', text:'Voce le imagens enviadas por clientes no WhatsApp. Descreva a imagem e transcreva TODO texto visivel (documentos, comprovantes, prints). Seja objetivo. Legenda do cliente: '+caption},
  {type:'image_url', image_url:{ url: 'data:'+mime+';base64,'+b64 }} ]}] };
return [{ json: { openaiBody: body } }];

const tenant = $('Buscar Tenant').item.json;
let faqs = tenant.kb_faqs;
if (typeof faqs !== 'string') faqs = JSON.stringify(faqs || []);
const history = $('Buscar Historico').item.json.history || [];
const system = `Voce e o assistente virtual da empresa "${tenant.name}" (nicho: ${tenant.niche}). Responda no WhatsApp de forma gentil, humana e conforme as regras do negocio.

BASE DE CONHECIMENTO (RAG):
${tenant.kb_text || ''}

FAQ:
${faqs}

CATALOGO E PRECOS:
${tenant.kb_catalogue || ''}

DIRETRIZES:
1. Responda estritamente com base nos dados acima.
2. NUNCA invente informacoes. Se nao souber, ofereca transferir para um atendente humano.
3. Se o cliente pedir atendente/humano/gerente, inclua a palavra reservada [TRANSFERIR_HUMANO] no fim.
4. Respostas curtas e faceis de ler no celular.`;
let msgs = history.map(h => ({ role: h.sender === 'customer' ? 'user' : 'assistant', content: (h.body || '...').toString() }));
const clean = [];
for (const m of msgs) { if (clean.length && clean[clean.length-1].role === m.role) clean[clean.length-1].content += "\n" + m.content; else clean.push({ role: m.role, content: m.content }); }
while (clean.length && clean[0].role !== 'user') clean.shift();
if (!clean.length) clean.push({ role:'user', content: $('Consolidar Mensagem').item.json.msgText || 'Ola' });
const body = { model: 'claude-sonnet-5', max_tokens: 600, temperature: 0.2, system, messages: clean };
return [{ json: { anthropicBody: body } }];

const r = $json;
let text = '';
if (Array.isArray(r.content)) text = r.content.map(c => c.text || '').join('').trim();
else text = (r.completion || '').trim();
let transfer = false;
if (text.includes('[TRANSFERIR_HUMANO]')) { transfer = true; text = text.replace('[TRANSFERIR_HUMANO]','').trim(); }
const lc = ($('Consolidar Mensagem').item.json.msgText || '').toLowerCase();
if (/atendente|humano|gerente|falar com/.test(lc)) transfer = true;
if (!text) text = 'Certo! Vou te transferir para um atendente humano agora mesmo. Um momento!';
return [{ json: { replyText: text, replyText_esc: text.replace(/'/g,"''"), shouldTransfer: transfer } }];

const tenant = $('Buscar Tenant').item.json;
const history = $('Buscar Historico').item.json.history || [];
const current = $('Consolidar Mensagem').item.json.msgText || '';
const prompt = `Voce e um Analista de Leads Senior. Classifique o lead com base na mensagem e no contexto.
EMPRESA: ${tenant.name} (nicho: ${tenant.niche})
MENSAGEM DO CLIENTE: "${current}"
HISTORICO: ${JSON.stringify(history.slice(-4))}

Retorne SOMENTE um JSON com as chaves:
- leadScore: "hot", "warm" ou "cold"
- leadReason: string curta
- suggestedTags: array de ate 3 strings curtas
- moveStageTo: "novo" | "contato" | "proposta" | "negociacao" | "fechado"
- customFields: objeto chave-valor com dados uteis extraidos`;
const body = { model:'gpt-4o-mini', temperature:0.1, response_format:{type:'json_object'}, messages:[{role:'system',content:'Responda SOMENTE com JSON valido, sem texto extra.'},{role:'user',content:prompt}] };
return [{ json: { openaiBody: body } }];

let cls = {};
try { cls = JSON.parse($json.choices[0].message.content || '{}'); } catch(e) { cls = {}; }
const contact = $('Upsert Contato').item.json;
const proc = $('Processar Claude').item.json;
const order = ['novo','contato','proposta','negociacao','fechado'];
let stage = contact.pipeline_stage || 'novo';
const target = cls.moveStageTo || '';
if (target && order.indexOf(target) > order.indexOf(stage)) stage = target;
let tags = Array.isArray(contact.tags) ? contact.tags.slice() : (function(){ try { return JSON.parse(contact.tags||'[]'); } catch(e){ return []; } })();
for (const t of (cls.suggestedTags || [])) if (t && !tags.includes(t)) tags.push(t);
let cf = (contact.custom_fields && typeof contact.custom_fields === 'object') ? contact.custom_fields : {};
const custom = Object.assign({}, cf, (cls.customFields || {}));
const aiOn = proc.shouldTransfer ? false : true;
return [{ json: { lead_score: cls.leadScore || 'warm', lead_reason: String(cls.leadReason || '').replace(/'/g,"''"), pipeline_stage: stage, tags_json: JSON.stringify(tags).replace(/'/g,"''"), custom_json: JSON.stringify(custom).replace(/'/g,"''"), ai_auto_reply: aiOn, shouldTransfer: proc.shouldTransfer, replyText: proc.replyText, replyText_esc: proc.replyText_esc } }];
